import hashlib
import time
from functools import wraps
from datetime import datetime, timedelta
from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
import sqlite3
from collections import defaultdict
from threading import Lock

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))

DB_NAME = 'auth_system.db'

rate_limit_storage = defaultdict(list)
rate_limit_lock = Lock()

def init_db():
    conn = sqlite3.connect(DB_NAME)
    cursor = conn.cursor()
    
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    ''')
    
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS tokens (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            token TEXT UNIQUE NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            expires_at TIMESTAMP NOT NULL,
            is_valid INTEGER DEFAULT 1,
            FOREIGN KEY (user_id) REFERENCES users (id)
        )
    ''')
    
    cursor.execute('''
        CREATE INDEX IF NOT EXISTS idx_token ON tokens(token)
    ''')
    
    cursor.execute('''
        CREATE INDEX IF NOT EXISTS idx_user_id ON tokens(user_id)
    ''')
    
    conn.commit()
    conn.close()

def get_db_connection():
    conn = sqlite3.connect(DB_NAME)
    conn.row_factory = sqlite3.Row
    return conn

def generate_secure_token():
    random_bytes = secrets.token_bytes(32)
    timestamp = str(time.time()).encode()
    combined = random_bytes + timestamp
    token = hashlib.sha256(combined).hexdigest()
    return token

def rate_limit(max_requests=5, window_seconds=60):
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            identifier = request.remote_addr
            current_time = time.time()
            
            with rate_limit_lock:
                requests = rate_limit_storage[identifier]
                requests = [req_time for req_time in requests if current_time - req_time < window_seconds]
                
                if len(requests) >= max_requests:
                    return jsonify({
                        'error': 'Rate limit exceeded',
                        'message': f'Maximum {max_requests} requests per {window_seconds} seconds'
                    }), 429
                
                requests.append(current_time)
                rate_limit_storage[identifier] = requests
            
            return f(*args, **kwargs)
        return wrapped
    return decorator

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        
        if 'Authorization' in request.headers:
            auth_header = request.headers['Authorization']
            try:
                token = auth_header.split(' ')[1]
            except IndexError:
                return jsonify({'error': 'Invalid token format'}), 401
        
        if not token:
            return jsonify({'error': 'Token is missing'}), 401
        
        conn = get_db_connection()
        cursor = conn.cursor()
        
        cursor.execute('''
            SELECT t.*, u.username, u.id as user_id
            FROM tokens t
            JOIN users u ON t.user_id = u.id
            WHERE t.token = ? AND t.is_valid = 1
        ''', (token,))
        
        token_data = cursor.fetchone()
        conn.close()
        
        if not token_data:
            return jsonify({'error': 'Invalid token'}), 401
        
        expires_at = datetime.fromisoformat(token_data['expires_at'])
        if datetime.utcnow() > expires_at:
            conn = get_db_connection()
            cursor = conn.cursor()
            cursor.execute('UPDATE tokens SET is_valid = 0 WHERE token = ?', (token,))
            conn.commit()
            conn.close()
            return jsonify({'error': 'Token has expired'}), 401
        
        return f(current_user={
            'id': token_data['user_id'],
            'username': token_data['username']
        }, *args, **kwargs)
    
    return decorated

@app.route('/api/register', methods=['POST'])
@rate_limit(max_requests=3, window_seconds=300)
def register():
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'error': 'Username and password are required'}), 400
    
    username = data['username'].strip()
    password = data['password']
    
    if len(username) < 3:
        return jsonify({'error': 'Username must be at least 3 characters'}), 400
    
    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400
    
    password_hash = generate_password_hash(password, method='pbkdf2:sha256', salt_length=16)
    
    conn = get_db_connection()
    cursor = conn.cursor()
    
    try:
        cursor.execute('INSERT INTO users (username, password_hash) VALUES (?, ?)',
                      (username, password_hash))
        conn.commit()
        user_id = cursor.lastrowid
        conn.close()
        
        return jsonify({
            'message': 'User registered successfully',
            'user_id': user_id,
            'username': username
        }), 201
        
    except sqlite3.IntegrityError:
        conn.close()
        return jsonify({'error': 'Username already exists'}), 409

@app.route('/api/login', methods=['POST'])
@rate_limit(max_requests=5, window_seconds=60)
def login():
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'error': 'Username and password are required'}), 400
    
    username = data['username'].strip()
    password = data['password']
    
    conn = get_db_connection()
    cursor = conn.cursor()
    
    cursor.execute('SELECT * FROM users WHERE username = ?', (username,))
    user = cursor.fetchone()
    
    if not user or not check_password_hash(user['password_hash'], password):
        conn.close()
        return jsonify({'error': 'Invalid username or password'}), 401
    
    token = generate_secure_token()
    expires_at = datetime.utcnow() + timedelta(hours=24)
    
    cursor.execute('''
        INSERT INTO tokens (user_id, token, expires_at)
        VALUES (?, ?, ?)
    ''', (user['id'], token, expires_at.isoformat()))
    
    conn.commit()
    conn.close()
    
    return jsonify({
        'message': 'Login successful',
        'token': token,
        'expires_at': expires_at.isoformat(),
        'user': {
            'id': user['id'],
            'username': user['username']
        }
    }), 200

